/**
 * Review Workbench — Full implementation.
 *
 * Features:
 * - MUI Tabs: 全部 / 待审核(pending) / 已确认(confirmed) / 已驳回(rejected)
 * - List view with InsightCard components
 * - Batch operations: select all + batch confirm/reject
 * - Empty state when no items
 */

import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Typography,
  Tabs,
  Tab,
  Button,
  ButtonGroup,
  Checkbox,
  FormControlLabel,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogContentText,
  DialogActions,
  TextField,
  Alert,
  Chip,
} from '@mui/material';
import RateReviewIcon from '@mui/icons-material/RateReview';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useInsightStore } from '@/shared/stores/insightStore';
import InsightCard from './InsightCard';
import ReviewLogDrawer from './ReviewLogDrawer';
import type { Insight, ReviewStatus } from '@/shared/types/insight';

const REVIEW_TABS: { value: ReviewStatus | 'all'; label: string }[] = [
  { value: 'all', label: '全部' },
  { value: 'pending', label: '待审核' },
  { value: 'confirmed', label: '已确认' },
  { value: 'rejected', label: '已驳回' },
];

const ReviewWorkbenchPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const insights = useInsightStore((s) => s.insights);
  const loadInsights = useInsightStore((s) => s.loadInsights);
  const confirmInsight = useInsightStore((s) => s.confirmInsight);
  const rejectInsight = useInsightStore((s) => s.rejectInsight);
  const editInsight = useInsightStore((s) => s.editInsight);
  const batchConfirm = useInsightStore((s) => s.batchConfirm);

  const [tab, setTab] = useState<ReviewStatus | 'all'>('pending');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Reject dialog
  const [rejectOpen, setRejectOpen] = useState(false);
  const [rejectReason, setRejectReason] = useState('');

  // Log drawer
  const [logDrawerInsight, setLogDrawerInsight] = useState<Insight | null>(null);
  const [logDrawerOpen, setLogDrawerOpen] = useState(false);

  const brandId = currentBrandId ?? '';

  useEffect(() => {
    if (brandId) {
      loadInsights(brandId);
    }
  }, [brandId, loadInsights]);

  // Filter by tab
  const filteredInsights = tab === 'all'
    ? insights
    : insights.filter((i) => i.reviewStatus === tab);

  const pendingCount = insights.filter((i) => i.reviewStatus === 'pending').length;
  const confirmedCount = insights.filter((i) => i.reviewStatus === 'confirmed').length;
  const rejectedCount = insights.filter((i) => i.reviewStatus === 'rejected').length;

  // Selection
  const allSelected =
    filteredInsights.length > 0 &&
    filteredInsights.every((i) => selectedIds.includes(i.id));

  const handleSelectAll = () => {
    if (allSelected) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredInsights.map((i) => i.id));
    }
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((sid) => sid !== id) : [...prev, id],
    );
  };

  // Batch confirm
  const handleBatchConfirm = async () => {
    await batchConfirm(selectedIds);
    setSelectedIds([]);
    if (brandId) await loadInsights(brandId);
  };

  // Batch reject
  const handleOpenBatchReject = () => {
    if (selectedIds.length === 0) return;
    setRejectReason('');
    setRejectOpen(true);
  };

  const handleBatchReject = async () => {
    if (!rejectReason.trim()) return;
    for (const id of selectedIds) {
      await rejectInsight(id, rejectReason.trim());
    }
    setRejectOpen(false);
    setSelectedIds([]);
    if (brandId) await loadInsights(brandId);
  };

  // Single actions
  const handleConfirm = async (id: string) => {
    await confirmInsight(id);
    if (brandId) await loadInsights(brandId);
  };

  const handleReject = async (id: string, reason: string) => {
    await rejectInsight(id, reason);
    if (brandId) await loadInsights(brandId);
  };

  const handleEdit = async (id: string, newContent: string) => {
    await editInsight(id, newContent);
    if (brandId) await loadInsights(brandId);
  };

  const handleOpenLogDrawer = (insight: Insight) => {
    setLogDrawerInsight(insight);
    setLogDrawerOpen(true);
  };

  // Empty state
  if (!brandId) {
    return (
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
        <Box sx={{ textAlign: 'center' }}>
          <RateReviewIcon sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6" color="text.secondary">
            请先选择品牌
          </Typography>
        </Box>
      </Box>
    );
  }

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <Box
        sx={{
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 1 }}>
          <Typography variant="h6" fontWeight={700}>
            ✅ 审核工作台
          </Typography>
        </Box>

        {/* Summary chips */}
        <Box sx={{ display: 'flex', gap: 1, mb: 1.5 }}>
          <Chip label={`全部 ${insights.length}`} size="small" variant="outlined" />
          <Chip label={`待审核 ${pendingCount}`} size="small" color="warning" />
          <Chip label={`已确认 ${confirmedCount}`} size="small" color="success" />
          <Chip label={`已驳回 ${rejectedCount}`} size="small" color="error" />
        </Box>

        {/* Batch toolbar */}
        {selectedIds.length > 0 && (
          <Alert
            severity="info"
            sx={{ mb: 1 }}
            action={
              <Box sx={{ display: 'flex', gap: 1 }}>
                <Button size="small" variant="contained" color="success" onClick={handleBatchConfirm}>
                  批量确认 ({selectedIds.length})
                </Button>
                <Button size="small" variant="contained" color="error" onClick={handleOpenBatchReject}>
                  批量驳回 ({selectedIds.length})
                </Button>
              </Box>
            }
          >
            已选择 {selectedIds.length} 条洞察
          </Alert>
        )}

        {/* Tabs */}
        <Tabs
          value={tab}
          onChange={(_, v) => {
            setTab(v);
            setSelectedIds([]);
          }}
          sx={{ minHeight: 36 }}
        >
          {REVIEW_TABS.map((t) => (
            <Tab
              key={t.value}
              value={t.value}
              label={
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                  <span>{t.label}</span>
                  {t.value === 'pending' && pendingCount > 0 && (
                    <Chip label={pendingCount} size="small" color="warning" sx={{ height: 18, fontSize: 10 }} />
                  )}
                </Box>
              }
              sx={{ minHeight: 36, py: 0.5 }}
            />
          ))}
        </Tabs>
      </Box>

      {/* Content */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
        {filteredInsights.length === 0 ? (
          <Box
            sx={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
              gap: 2,
            }}
          >
            <RateReviewIcon sx={{ fontSize: 48, color: 'text.disabled' }} />
            <Typography variant="body1" color="text.secondary">
              {tab === 'pending'
                ? '暂无待审核项，请先运行 AI 分析'
                : tab === 'confirmed'
                  ? '暂无已确认的洞察'
                  : tab === 'rejected'
                    ? '暂无已驳回的洞察'
                    : '暂无洞察数据'}
            </Typography>
            {tab !== 'pending' && (
              <Button variant="outlined" onClick={() => setTab('pending')}>
                查看待审核项
              </Button>
            )}
          </Box>
        ) : (
          <>
            {/* Select all */}
            <Box sx={{ mb: 1, display: 'flex', alignItems: 'center' }}>
              <FormControlLabel
                control={
                  <Checkbox
                    checked={allSelected}
                    onChange={handleSelectAll}
                    size="small"
                  />
                }
                label={
                  <Typography variant="caption" color="text.secondary">
                    全选 ({filteredInsights.length})
                  </Typography>
                }
              />
            </Box>

            {/* Insight list */}
            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
              {filteredInsights.map((insight) => (
                <Box key={insight.id} sx={{ display: 'flex', gap: 1, alignItems: 'flex-start' }}>
                  <Checkbox
                    checked={selectedIds.includes(insight.id)}
                    onChange={() => handleToggleSelect(insight.id)}
                    size="small"
                    sx={{ mt: 1.5 }}
                  />
                  <Box sx={{ flex: 1 }}>
                    <InsightCard
                      insight={insight}
                      onConfirm={handleConfirm}
                      onReject={handleReject}
                      onEdit={handleEdit}
                    />
                    {/* View log button */}
                    <Button
                      size="small"
                      variant="text"
                      sx={{ fontSize: 11, mt: 0.25 }}
                      onClick={() => handleOpenLogDrawer(insight)}
                    >
                      📋 查看审核日志
                    </Button>
                  </Box>
                </Box>
              ))}
            </Box>
          </>
        )}
      </Box>

      {/* Batch reject dialog */}
      <Dialog open={rejectOpen} onClose={() => setRejectOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>批量驳回</DialogTitle>
        <DialogContent>
          <DialogContentText sx={{ mb: 2 }}>
            将对选中的 {selectedIds.length} 条洞察进行驳回。请输入驳回理由：
          </DialogContentText>
          <TextField
            autoFocus
            multiline
            rows={3}
            fullWidth
            placeholder="驳回理由..."
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRejectOpen(false)}>取消</Button>
          <Button
            variant="contained"
            color="error"
            onClick={handleBatchReject}
            disabled={!rejectReason.trim()}
          >
            确认驳回 {selectedIds.length} 条
          </Button>
        </DialogActions>
      </Dialog>

      {/* Review log drawer */}
      <ReviewLogDrawer
        open={logDrawerOpen}
        onClose={() => setLogDrawerOpen(false)}
        insight={logDrawerInsight}
      />
    </Box>
  );
};

export default ReviewWorkbenchPage;
