/**
 * InsightCard — Displays a single insight with review status styling.
 *
 * Features:
 * - Confidence badge (high ≥0.7 green, medium 0.4-0.7 amber, low <0.4 grey)
 * - Type tag: demand / barrier / competitor / strategy
 * - Review status borders: pending (highlighted), confirmed (green), rejected (red)
 * - Collapsible source comments list
 * - Edit area for confirmed items
 */

import React, { useState } from 'react';
import {
  Card,
  CardContent,
  CardActions,
  Typography,
  Chip,
  Box,
  Collapse,
  IconButton,
  Tooltip,
} from '@mui/material';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import ExpandLessIcon from '@mui/icons-material/ExpandLess';
import type { Insight } from '@/shared/types/insight';
import ReviewActionBar from './ReviewActionBar';

interface InsightCardProps {
  insight: Insight;
  onConfirm: (id: string) => void;
  onReject: (id: string, reason: string) => void;
  onEdit: (id: string, newContent: string) => void;
}

/** Confidence level display */
function getConfidenceChip(confidence: number) {
  if (confidence >= 0.7) {
    return <Chip label="高" size="small" color="success" variant="outlined" sx={{ fontSize: 11 }} />;
  }
  if (confidence >= 0.4) {
    return <Chip label="中" size="small" color="warning" variant="outlined" sx={{ fontSize: 11 }} />;
  }
  return <Chip label="低" size="small" sx={{ fontSize: 11, color: 'text.secondary' }} variant="outlined" />;
}

/** Type label and color */
function getTypeLabel(type: Insight['type']) {
  switch (type) {
    case 'demand':
      return { label: '需求', color: 'primary' as const };
    case 'barrier':
      return { label: '障碍', color: 'error' as const };
    case 'competitor':
      return { label: '竞品', color: 'warning' as const };
    case 'strategy':
      return { label: '策略', color: 'info' as const };
    default:
      return { label: '其他', color: 'default' as const };
  }
}

const InsightCard: React.FC<InsightCardProps> = ({
  insight,
  onConfirm,
  onReject,
  onEdit,
}) => {
  const [expanded, setExpanded] = useState(false);
  const typeInfo = getTypeLabel(insight.type);

  const borderColor =
    insight.reviewStatus === 'confirmed'
      ? 'success.main'
      : insight.reviewStatus === 'rejected'
        ? 'error.main'
        : 'divider';

  const borderWidth = insight.reviewStatus === 'pending' ? 1.5 : 1;

  return (
    <Card
      sx={{
        border: `${borderWidth}px solid`,
        borderColor,
        bgcolor:
          insight.reviewStatus === 'confirmed'
            ? 'success.50'
            : insight.reviewStatus === 'rejected'
              ? 'error.50'
              : 'background.paper',
        '& .MuiCardContent-root': { pb: 1 },
      }}
    >
      <CardContent>
        {/* Header row */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1, flexWrap: 'wrap' }}>
          <Chip
            label={typeInfo.label}
            size="small"
            color={typeInfo.color}
            sx={{ fontWeight: 600, fontSize: 11 }}
          />
          {getConfidenceChip(insight.confidence)}
          {insight.reviewStatus === 'confirmed' && (
            <Chip label="已确认" size="small" color="success" sx={{ fontSize: 11, ml: 'auto' }} />
          )}
          {insight.reviewStatus === 'rejected' && (
            <Chip label="已驳回" size="small" color="error" sx={{ fontSize: 11, ml: 'auto' }} />
          )}
        </Box>

        {/* Title */}
        <Typography variant="subtitle2" fontWeight={600} gutterBottom>
          {insight.title}
        </Typography>

        {/* Content */}
        <Typography
          variant="body2"
          color="text.secondary"
          sx={{
            whiteSpace: 'pre-wrap',
            wordBreak: 'break-word',
            mb: insight.sourceCommentsQuote?.length ? 1 : 0,
          }}
        >
          {insight.editedContent ?? insight.content}
        </Typography>

        {/* Source comments count */}
        {insight.sourceCommentsQuote && insight.sourceCommentsQuote.length > 0 && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
            <Typography variant="caption" color="text.disabled">
              支撑评论 {insight.sourceCommentsQuote.length} 条
            </Typography>
            <IconButton size="small" onClick={() => setExpanded(!expanded)}>
              {expanded ? <ExpandLessIcon fontSize="small" /> : <ExpandMoreIcon fontSize="small" />}
            </IconButton>
          </Box>
        )}

        {/* Collapse: source comments */}
        <Collapse in={expanded}>
          <Box
            sx={{
              mt: 1,
              p: 1,
              borderRadius: 1,
              bgcolor: 'action.hover',
              maxHeight: 200,
              overflow: 'auto',
            }}
          >
            {insight.sourceCommentsQuote.map((quote, idx) => (
              <Typography
                key={idx}
                variant="caption"
                color="text.secondary"
                sx={{ display: 'block', mb: 0.5, fontStyle: 'italic' }}
              >
                "{quote}"
              </Typography>
            ))}
          </Box>
        </Collapse>

        {/* Edited indicator */}
        {insight.editedContent && (
          <Typography variant="caption" color="warning.main" sx={{ mt: 0.5, display: 'block' }}>
            ✏️ 已人工编辑
          </Typography>
        )}

        {/* Reject reason */}
        {insight.reviewStatus === 'rejected' && (
          <Box sx={{ mt: 1 }}>
            {insight.reviewLog
              .filter((l) => l.action === 'rejected')
              .slice(-1)
              .map((log, idx) => (
                <Typography key={idx} variant="caption" color="error.main">
                  ❌ 驳回理由: {log.changes ?? '未提供'}
                </Typography>
              ))}
          </Box>
        )}

        {/* Confirmed time */}
        {insight.reviewStatus === 'confirmed' && (
          <Typography variant="caption" color="success.main" sx={{ mt: 0.5, display: 'block' }}>
            ✅{' '}
            {insight.reviewLog
              .filter((l) => l.action === 'confirmed')
              .slice(-1)[0]
              ?.timestamp?.split('T')[0] ?? ''}
          </Typography>
        )}
      </CardContent>

      {/* Actions for pending items */}
      {insight.reviewStatus === 'pending' && (
        <CardActions sx={{ px: 2, pb: 1.5, pt: 0 }}>
          <ReviewActionBar
            insightId={insight.id}
            onConfirm={onConfirm}
            onReject={onReject}
            onEdit={onEdit}
          />
        </CardActions>
      )}
    </Card>
  );
};

export default InsightCard;
