/**
 * ReviewLogDrawer — Displays the complete review log timeline for an insight.
 *
 * Features:
 * - MUI Drawer from the right side
 * - Timeline-style display of review actions
 * - Each entry: operator, timestamp, action type, changes
 */

import React from 'react';
import {
  Drawer,
  Box,
  Typography,
  IconButton,
  Divider,
  Chip,
} from '@mui/material';
import CloseIcon from '@mui/icons-material/Close';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import EditIcon from '@mui/icons-material/Edit';
import CancelIcon from '@mui/icons-material/Cancel';
import AddCircleIcon from '@mui/icons-material/AddCircle';
import type { Insight, ReviewLog } from '@/shared/types/insight';

interface ReviewLogDrawerProps {
  open: boolean;
  onClose: () => void;
  insight: Insight | null;
}

/** Icon mapping for review actions */
function getActionIcon(action: ReviewLog['action']) {
  switch (action) {
    case 'created':
      return <AddCircleIcon fontSize="small" color="info" />;
    case 'confirmed':
      return <CheckCircleIcon fontSize="small" color="success" />;
    case 'edited':
      return <EditIcon fontSize="small" color="warning" />;
    case 'rejected':
      return <CancelIcon fontSize="small" color="error" />;
    default:
      return <AddCircleIcon fontSize="small" color="disabled" />;
  }
}

/** Action label in Chinese */
function getActionLabel(action: ReviewLog['action']): string {
  switch (action) {
    case 'created':
      return 'AI 生成';
    case 'confirmed':
      return '已确认';
    case 'edited':
      return '已编辑';
    case 'rejected':
      return '已驳回';
    default:
      return action;
  }
}

/** Action color */
function getActionColor(action: ReviewLog['action']) {
  switch (action) {
    case 'created':
      return 'info' as const;
    case 'confirmed':
      return 'success' as const;
    case 'edited':
      return 'warning' as const;
    case 'rejected':
      return 'error' as const;
    default:
      return 'default' as const;
  }
}

const ReviewLogDrawer: React.FC<ReviewLogDrawerProps> = ({ open, onClose, insight }) => {
  if (!insight) return null;

  return (
    <Drawer
      anchor="right"
      open={open}
      onClose={onClose}
      PaperProps={{
        sx: {
          width: 400,
          maxWidth: '90vw',
          p: 0,
        },
      }}
    >
      {/* Header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Box>
          <Typography variant="subtitle1" fontWeight={700}>
            📋 审核日志
          </Typography>
          <Typography variant="caption" color="text.secondary">
            {insight.title}
          </Typography>
        </Box>
        <IconButton onClick={onClose} size="small">
          <CloseIcon />
        </IconButton>
      </Box>

      {/* Status summary */}
      <Box sx={{ px: 2, py: 1.5, display: 'flex', gap: 1, alignItems: 'center' }}>
        <Typography variant="caption" color="text.secondary">
          当前状态:
        </Typography>
        <Chip
          label={
            insight.reviewStatus === 'confirmed'
              ? '已确认'
              : insight.reviewStatus === 'rejected'
                ? '已驳回'
                : '待审核'
          }
          size="small"
          color={
            insight.reviewStatus === 'confirmed'
              ? 'success'
              : insight.reviewStatus === 'rejected'
                ? 'error'
                : 'warning'
          }
        />
      </Box>

      <Divider />

      {/* Timeline */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
        {insight.reviewLog.length === 0 ? (
          <Typography variant="body2" color="text.secondary">
            暂无审核记录
          </Typography>
        ) : (
          <Box sx={{ position: 'relative' }}>
            {/* Timeline line */}
            <Box
              sx={{
                position: 'absolute',
                left: 16,
                top: 8,
                bottom: 8,
                width: 2,
                bgcolor: 'divider',
              }}
            />

            {[...insight.reviewLog].reverse().map((log, idx) => (
              <Box
                key={idx}
                sx={{
                  position: 'relative',
                  pl: 5,
                  pb: idx < insight.reviewLog.length - 1 ? 2.5 : 0,
                }}
              >
                {/* Dot */}
                <Box
                  sx={{
                    position: 'absolute',
                    left: 12,
                    top: 6,
                    width: 10,
                    height: 10,
                    borderRadius: '50%',
                    bgcolor: `${getActionColor(log.action)}.main`,
                    border: '2px solid',
                    borderColor: 'background.paper',
                    zIndex: 1,
                  }}
                />

                {/* Card */}
                <Box
                  sx={{
                    p: 1.5,
                    borderRadius: 1.5,
                    bgcolor: 'action.hover',
                    border: '1px solid',
                    borderColor: 'divider',
                  }}
                >
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5 }}>
                    {getActionIcon(log.action)}
                    <Chip
                      label={getActionLabel(log.action)}
                      size="small"
                      color={getActionColor(log.action)}
                      sx={{ fontSize: 11, height: 20 }}
                    />
                  </Box>
                  <Typography variant="caption" color="text.secondary" sx={{ display: 'block' }}>
                    {log.operator} · {new Date(log.timestamp).toLocaleString()}
                  </Typography>
                  {log.changes && (
                    <Typography
                      variant="caption"
                      sx={{
                        mt: 0.5,
                        display: 'block',
                        color: log.action === 'rejected' ? 'error.main' : 'text.secondary',
                        fontStyle: 'italic',
                      }}
                    >
                      {log.action === 'rejected' ? '驳回理由: ' : '变更: '}
                      {log.changes}
                    </Typography>
                  )}
                </Box>
              </Box>
            ))}
          </Box>
        )}
      </Box>

      {/* Original vs Edited */}
      {insight.originalContent && (
        <Box sx={{ borderTop: '1px solid', borderColor: 'divider', p: 2 }}>
          <Typography variant="caption" fontWeight={700} color="text.secondary">
            原始内容:
          </Typography>
          <Typography variant="caption" color="text.secondary" sx={{ whiteSpace: 'pre-wrap', mt: 0.5, display: 'block' }}>
            {insight.originalContent}
          </Typography>
        </Box>
      )}
      {insight.editedContent && (
        <Box sx={{ borderTop: '1px solid', borderColor: 'divider', p: 2 }}>
          <Typography variant="caption" fontWeight={700} color="warning.main">
            编辑后内容:
          </Typography>
          <Typography variant="caption" color="text.secondary" sx={{ whiteSpace: 'pre-wrap', mt: 0.5, display: 'block' }}>
            {insight.editedContent}
          </Typography>
        </Box>
      )}
    </Drawer>
  );
};

export default ReviewLogDrawer;
